# AI-hint: A migration script that replaces a broken manual ReadKey loop with Read-Host -MaskInput in mios-build-local.ps1 to ensure pasted tokens are correctly captured in PowerShell 7.x.
# AI-related: mios-build-local
<#
.SYNOPSIS  Fix token paste bug in mios-build-local.ps1
.DESCRIPTION
    The [Console]::ReadKey loop doesn't detect Enter after paste in PS 7.6.
    Replace with Read-Host -MaskInput (PS 7.1+, handles paste natively).

    Run from repo root:
      cd $env:USERPROFILE\OneDrive\Documents\GitHub\MiOS   # or wherever the repo is
      .\fix-token-input.ps1
#>
$ErrorActionPreference = "Stop"

if (-not (Test-Path "mios-build-local.ps1")) {
    Write-Host "  ERROR: Run from \MiOS repo root" -ForegroundColor Red; exit 1
}

$file = "mios-build-local.ps1"
$content = [System.IO.File]::ReadAllText((Resolve-Path $file).Path)

# Old: custom ReadKey loop that breaks on paste
$old = @'
        if ($Secret) {
            $secBuf = ""
            while ($true) {
                $key = [Console]::ReadKey($true)
                if ($key.Key -eq 'Enter') { Write-Host ""; break }
                if ($key.Key -eq 'Backspace') {
                    if ($secBuf.Length -gt 0) { $secBuf = $secBuf.Substring(0, $secBuf.Length - 1); Write-Host "`b `b" -NoNewline }
                } else {
                    $secBuf += $key.KeyChar; Write-Host "*" -NoNewline
                }
            }
            $buf = $secBuf
'@

# New: Read-Host -MaskInput (PS 7.1+, handles paste correctly)
$new = @'
        if ($Secret) {
            $buf = Read-Host -MaskInput
'@

if ($content.Contains($old)) {
    $content = $content.Replace($old, $new)
    [System.IO.File]::WriteAllText(
        (Resolve-Path $file).Path, $content,
        [System.Text.UTF8Encoding]::new($true)  # BOM for PS file
    )
    Write-Host "  [ok] Token input fixed: Read-Host -MaskInput (handles paste)" -ForegroundColor Green
} else {
    # Try with normalized line endings
    $content = $content -replace "`r`n", "`n"
    $old = $old -replace "`r`n", "`n"
    $new = $new -replace "`r`n", "`n"
    if ($content.Contains($old)) {
        $content = $content.Replace($old, $new)
        [System.IO.File]::WriteAllText(
            (Resolve-Path $file).Path, $content,
            [System.Text.UTF8Encoding]::new($true)
        )
        Write-Host "  [ok] Token input fixed (LF normalized)" -ForegroundColor Green
    } else {
        Write-Host "  [x] ReadKey pattern not found -- checking manually" -ForegroundColor Red
        Write-Host "  Line 91:" -ForegroundColor Yellow
        Get-Content $file | Select-Object -Skip 90 -First 1
    }
}

git add mios-build-local.ps1
git commit -m "fix: token paste bug -- replace ReadKey loop with Read-Host -MaskInput`n`n[Console]::ReadKey loop in Read-Timed -Secret doesn't detect Enter`nafter paste in PowerShell 7.6/Windows Terminal. Each Enter press`nadds another masked character instead of submitting.`n`nRead-Host -MaskInput (PS 7.1+) handles paste, Enter, backspace`nnatively with * masking."
git push origin main 2>&1 | ForEach-Object { Write-Host "  $_" }
if ($LASTEXITCODE -eq 0) {
    Write-Host "`n  [ok] Pushed. Re-clone and rebuild.`n" -ForegroundColor Green
}

# AI-hint: Parses Markdown files and metadata blocks to generate a JSON manifest of the project structure, providing agents with a searchable index of documentation, knowledge blocks, and file metadata.
# AI-functions: parse_markdown_metadata, generate_json_manifest, generate_gzipped_manifest
import os
import json
import re
import gzip

def parse_markdown_metadata(content):
    """Simple parser to extract title and metadata from Markdown."""
    title_match = re.search(r'^#\s+(.+)$', content, re.MULTILINE)
    title = title_match.group(1).strip() if title_match else "Untitled"

    # Extract blockquotes/metadata lines like "> **Key:** Value"
    metadata = {}
    meta_matches = re.findall(r'^>\s+\*\*(.+?):\*\*\s+(.+)$', content, re.MULTILINE)
    for key, value in meta_matches:
        metadata[key.strip().lower().replace(" ", "_")] = value.strip()

    # Extract json:knowledge block
    knowledge_block = {}
    kb_match = re.search(r'```json:knowledge\s*\n(.*?)\n```', content, re.DOTALL)
    if kb_match:
        try:
            knowledge_block = json.loads(kb_match.group(1))
        except json.JSONDecodeError:
            pass

    return title, metadata, knowledge_block

def generate_json_manifest(target_dir, output_file, recursive=True, ignore_dirs=None):
    if ignore_dirs is None:
        ignore_dirs = {".git", ".venv", "output", "__pycache__", "agents/research"}

    manifest = {
        "source_directory": target_dir,
        "entries": []
    }

    if not os.path.exists(target_dir):
        return

    for root, dirs, files in os.walk(target_dir):
        if not recursive and root != target_dir:
            continue

        # Filter out ignored directories. SORT dirs (controls os.walk recursion
        # order) + files (entry order) so the manifest is byte-reproducible across
        # environments -- os.walk does NOT guarantee order, which would otherwise
        # make the WS-10 regenerate-and-diff gate flap (operator 2026-06-19).
        dirs[:] = sorted(d for d in dirs if d not in ignore_dirs)

        for file in sorted(files):
            if file == os.path.basename(output_file):
                continue

            file_path = os.path.join(root, file)
            rel_path = os.path.relpath(file_path, start=os.getcwd())

            try:
                entry = {
                    "path": rel_path
                }

                # Handle different file types
                if file.endswith(".md"):
                    with open(file_path, 'r', encoding='utf-8') as f:
                        content = f.read()
                    title, metadata, knowledge_block = parse_markdown_metadata(content)
                    entry.update({
                        "title": title,
                        "type": "documentation",
                        "metadata": metadata,
                        "knowledge": knowledge_block,
                        "content_preview": content[:500] + "..." if len(content) > 500 else content,
                        "full_content": content
                    })
                    manifest["entries"].append(entry)
                elif file.endswith(".json"):
                    with open(file_path, 'r', encoding='utf-8') as f:
                        try:
                            data = json.load(f)
                            title = file
                            if isinstance(data, dict):
                                title = data.get("artifact_name", file)
                            entry.update({
                                "title": title,
                                "type": "structured_data",
                                "structured_data": data
                            })
                            manifest["entries"].append(entry)
                        except json.JSONDecodeError:
                            continue
                elif file.endswith((".sh", ".ps1", ".py", ".toml", "Containerfile", "Justfile")):
                    with open(file_path, 'r', encoding='utf-8') as f:
                        try:
                            content = f.read()
                            entry.update({
                                "title": file,
                                "type": "source_code",
                                "full_content": content
                            })
                            manifest["entries"].append(entry)
                        except UnicodeDecodeError:
                            continue
            except (FileNotFoundError, PermissionError, OSError):
                continue

    with open(output_file, 'w', encoding='utf-8') as f:
        json.dump(manifest, f, indent=2)
    print(f"Generated {output_file}")

def generate_gzipped_manifest(target_dir, output_file, recursive=True, ignore_dirs=None):
    if ignore_dirs is None:
        ignore_dirs = {".git", ".venv", "output", "__pycache__", "agents/research"}

    manifest = {
        "source_directory": target_dir,
        "entries": []
    }

    if not os.path.exists(target_dir):
        return

    for root, dirs, files in os.walk(target_dir):
        if not recursive and root != target_dir:
            continue

        dirs[:] = sorted(d for d in dirs if d not in ignore_dirs)

        for file in sorted(files):
            if file == os.path.basename(output_file):
                continue

            file_path = os.path.join(root, file)
            rel_path = os.path.relpath(file_path, start=os.getcwd())

            try:
                entry = {
                    "path": rel_path
                }

                if file.endswith(".json.gz"):
                    with gzip.open(file_path, 'rt', encoding='utf-8') as f:
                        try:
                            data = json.load(f)
                            title = file
                            if isinstance(data, dict):
                                title = data.get("artifact_name", file)
                            entry.update({
                                "title": title,
                                "type": "structured_data",
                                "structured_data": data
                            })
                            manifest["entries"].append(entry)
                        except json.JSONDecodeError:
                            continue
                elif file.endswith(".json"):
                    with open(file_path, 'r', encoding='utf-8') as f:
                        try:
                            data = json.load(f)
                            title = file
                            if isinstance(data, dict):
                                title = data.get("artifact_name", file)
                            entry.update({
                                "title": title,
                                "type": "structured_data",
                                "structured_data": data
                            })
                            manifest["entries"].append(entry)
                        except json.JSONDecodeError:
                            continue
            except (FileNotFoundError, PermissionError, OSError, UnicodeDecodeError):
                continue

    with gzip.open(output_file, 'wt', encoding='utf-8') as f:
        json.dump(manifest, f, indent=2)
    print(f"Generated {output_file}")

if __name__ == "__main__":
    # Categories to manifest
    targets = [
        ("specs", "specs/manifest.json", False), # Non-recursive for flat specs (Wiki)
        (".ai/foundation/memories", ".ai/foundation/memories/manifest.json", False),
        ("artifacts", "artifacts/manifest.json.gz", False),
        ("automation", "automation/manifest.json", True),
        ("tools", "tools/manifest.json", True),
        ("overlay", "manifest.json", True),
        ("evals", "evals/manifest.json", True),
        ("bib-configs", "bib-configs/manifest.json", True),
        ("agents/research", "agents/research/manifest.json", True),
        (".", "root-manifest.json", False) # Non-recursive for root
    ]

    for target_dir, output_file, recursive in targets:
        if output_file.endswith(".gz"):
            generate_gzipped_manifest(target_dir, output_file, recursive)
        else:
            generate_json_manifest(target_dir, output_file, recursive)

# AI-hint: Parses codebase files to extract metadata, redact secrets, and compile a compressed `repo-rag-snapshot.json.gz` file to provide a unified semantic knowledge base for RAG-based AI agents.
# AI-functions: redact_secrets, parse_metadata, generate_unified_knowledge
import os
import json
import re
import gzip
from datetime import datetime

def redact_secrets(content):
    """Redacts common secret patterns from content."""
    patterns = [
        (r'(?i)(api_key|secret|password|token|private_key)(\s*[:=]\s*)([^\s,]+)', r'\1\2[REDACTED]'),
        (r'AIza[0-9A-Za-z-_]{35}', '[REDACTED]'),  # Cloud API Keys
        (r'sk-[0-9A-Za-z]{48}', '[REDACTED]'),      # OpenAI Keys
    ]
    redacted = content
    for pattern, replacement in patterns:
        redacted = re.sub(pattern, replacement, redacted)
    return redacted

def parse_metadata(content, file_path):
    """Extracts structured metadata and patterns from content."""
    meta = {
        "title": os.path.basename(file_path),
        "summary": "",
        "patterns": [],
        "technologies": [],
        "logic_type": "unknown"
    }

    # Extract markdown title
    title_match = re.search(r'^#\s+(.+)$', content, re.MULTILINE)
    if title_match:
        meta["title"] = title_match.group(1).strip()

    # Extract json:knowledge block
    kb_match = re.search(r'```json:knowledge\s*\n(.*?)\n```', content, re.DOTALL)
    if kb_match:
        try:
            kb = json.loads(kb_match.group(1))
            meta.update(kb)
        except json.JSONDecodeError:
            pass

    # Basic pattern matching for technologies
    tech_keywords = ["bootc", "podman", "quadlet", "k3s", "ceph", "nvidia", "gnome", "selinux", "greenboot", "composefs"]
    for tech in tech_keywords:
        if tech in content.lower():
            meta["technologies"].append(tech)

    return meta

def generate_unified_knowledge(output_file="artifacts/repo-rag-snapshot.json.gz"):
    print(f" Flattening Historical Knowledge into UKB: {output_file}...")

    ignore_dirs = {".git", ".venv", "__pycache__", "node_modules", "artifacts"}
    snapshot = {
        "metadata": {
            "project": "MiOS",
            "timestamp": datetime.now().isoformat(),
            "scope": "Flattened Historical & Semantic Knowledge",
            "rag_format_version": "2.0",
            "foss_compliant": True,
            "ai_native": True
        },
        "semantic_index": {
            "core_blueprints": [],
            "engineering_patterns": [],
            "historical_context": [],
            "automation_logic": [],
            "validation_suites": []
        },
        "knowledge_nodes": []
    }

    # 1. Capture and Flatten Repository Knowledge
    for root, dirs, files in os.walk("."):
        dirs[:] = [d for d in dirs if d not in ignore_dirs]

        for file in files:
            file_path = os.path.join(root, file)
            rel_path = os.path.relpath(file_path, start=os.getcwd())

            # Skip non-text files and large files
            if not file.endswith((".md", ".json", ".sh", ".py", ".ps1", ".toml", ".yaml", ".yml", ".conf", ".txt", ".log", "Containerfile", "Justfile")) and not file.startswith("."):
                continue

            if os.path.getsize(file_path) > 1024 * 1024:
                continue

            try:
                with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()

                content = redact_secrets(content)
                meta = parse_metadata(content, rel_path)

                # Determine category and index
                category = "other"
                index_key = None

                if rel_path.startswith("specs/core/"): 
                    category = "core_foundation"
                    index_key = "core_blueprints"
                elif rel_path.startswith("specs/engineering/"): 
                    category = "engineering"
                    index_key = "engineering_patterns"
                elif rel_path.startswith("specs/memory/") or rel_path.startswith("specs/changelogs/") or rel_path.startswith("specs/audit/"):
                    category = "history"
                    index_key = "historical_context"
                elif rel_path.startswith("automation/"): 
                    category = "automation"
                    index_key = "automation_logic"
                elif rel_path.startswith("evals/"): 
                    category = "validation"
                    index_key = "validation_suites"
                elif rel_path.startswith("specs/knowledge/"):
                    category = "research"
                    index_key = "engineering_patterns"

                node = {
                    "path": rel_path,
                    "category": category,
                    "metadata": meta,
                    "content": content
                }

                snapshot["knowledge_nodes"].append(node)
                if index_key:
                    snapshot["semantic_index"][index_key].append({
                        "path": rel_path,
                        "title": meta["title"],
                        "technologies": meta["technologies"]
                    })

            except Exception as e:
                print(f"[!] Could not process {rel_path}: {e}")

    # Ensure artifacts directory exists
    os.makedirs(os.path.dirname(output_file), exist_ok=True)

    with gzip.open(output_file, 'wt', encoding='utf-8') as f:
        json.dump(snapshot, f, indent=2)

    print(f"[ok] Flattened UKB generated with {len(snapshot['knowledge_nodes'])} semantic nodes.")

if __name__ == "__main__":
    generate_unified_knowledge()

# AI-hint: Updates metadata in wiki markdown files by injecting current version and RAG sync timestamps into JSON blocks to ensure documentation reflects the latest system state and artifact availability.
# AI-functions: get_last_rag_sync, get_version, sync_json_embeds, update_knowledge, update_status, sync_wiki
import os
import re
import json
from datetime import datetime

def get_last_rag_sync():
    rag_file = "artifacts/repo-rag-snapshot.json.gz"
    if os.path.exists(rag_file):
        mtime = os.path.getmtime(rag_file)
        return datetime.fromtimestamp(mtime).isoformat()
    return datetime.now().isoformat()

def get_version():
    if os.path.exists("VERSION"):
        with open("VERSION", "r") as f:
            return f.read().strip()
    return "v0.2.0"

def sync_json_embeds(file_path):
    if not os.path.exists(file_path):
        return

    with open(file_path, 'r') as f:
        content = f.read()

    version = get_version()
    rag_sync = get_last_rag_sync()

    # 1. Update json:knowledge blocks
    def update_knowledge(match):
        try:
            data = json.loads(match.group(1))
            data["last_rag_sync"] = rag_sync
            data["version"] = version
            return f"```json:knowledge\n{json.dumps(data, indent=2)}\n```"
        except:
            return match.group(0)

    content = re.sub(r"```json:knowledge\n(.*?)\n```", update_knowledge, content, flags=re.DOTALL)

    # 2. Update status blocks (specifically for README.md)
    def update_status(match):
        try:
            data = json.loads(match.group(1))
            if "baseline" in data:
                data["baseline"] = f"v{version}"
            if "last_build" in data or True: # Force add if not present for tracking
                 data["last_sync"] = rag_sync
            return f"```json\n{json.dumps(data, indent=2)}\n```"
        except:
            return match.group(0)

    # Targeted regex for the status-style JSON blocks (not knowledge)
    content = re.sub(r"#  'MiOS': Immutable Cloud-Native Workstation\n\n```json\n(.*?)\n```", 
                     r"#  'MiOS': Immutable Cloud-Native Workstation\n\n```json\n\1\n```", content, flags=re.DOTALL)
    # Actually apply the update to any generic json block that looks like a status block
    content = re.sub(r"```json\n(\{.*?\})\n```", update_status, content, flags=re.DOTALL)

    with open(file_path, 'w') as f:
        f.write(content)
    print(f"[ok] Propagated sync values to {file_path}")

def sync_wiki():
    print(" Syncing Wiki Documentation...")

    # 1. Update Scripts Index
    automation_dir = "automation"
    automation_doc = "specs/engineering/2026-04-26-Artifact-ENG-002-Scripts-Index.md"

    knowledge_meta = {
        "summary": "Automated index of all 'MiOS' automation automation.",
        "logic_type": "automation",
        "tags": ["automation", "automation", "index"],
        "version": get_version(),
        "last_rag_sync": get_last_rag_sync()
    }

    content = f"""<!--  'MiOS' Artifact | Proprietor: 'MiOS' Project | https://github.com/MiOS-DEV/mios -->
#  'MiOS' Scripts Index
> **Generated:** {datetime.now().isoformat()}
> **Status:** Automated Sync

```json:knowledge
{json.dumps(knowledge_meta, indent=2)}
```

This file provides a machine-readable and human-readable index of all automation automation in the `automation/` directory.

"""
    for script in sorted(os.listdir(automation_dir)):
        if script.endswith(".sh"):
            path = os.path.join(automation_dir, script)
            # Try to extract a description from the first few lines
            description = "No description available."
            try:
                with open(path, 'r') as f:
                    lines = f.readlines()
                    for line in lines:
                        clean_line = line.strip()
                        if clean_line.startswith("# ") and not clean_line.startswith("#!") and "===" not in clean_line:
                            description = clean_line[2:].strip()
                            if description:
                                break
            except:
                pass
            content += f"## `{script}`\n- **Path:** `{path}`\n- **Description:** {description}\n\n"

    content += "<!--  'MiOS' Proprietary Artifact | Copyright (c) 2026 'MiOS' Project -->"

    os.makedirs(os.path.dirname(automation_doc), exist_ok=True)
    with open(automation_doc, 'w') as f:
        f.write(content)
    print(f"[ok] Updated {automation_doc}")

    # 2. Sync embeds in key files
    target_files = ["README.md", "usr/share/mios/ai/INDEX.md", "usr/share/mios/ai/INDEX.md", "usr/share/mios/ai/INDEX.md", "usr/share/mios/ai/INDEX.md", "specs/Home.md"]
    for f in target_files:
        sync_json_embeds(f)

if __name__ == "__main__":
    sync_wiki()

# AI-hint: PowerShell entry point for Windows environments to build the MiOS OCI image via Docker and convert it into a bootable VHDX, raw, or qcow2 disk image using bootc-image-builder.
# AI-related: mios-bib
# AI-functions: Write-Step, Write-Ok, Write-Warn, Write-Fail
#Requires -Version 5.1
<#
.SYNOPSIS
    'MiOS' local build entry point for Windows (Docker Desktop + WSL2).

.DESCRIPTION
    Builds the 'MiOS' OCI image locally using Docker Desktop (WSL2 backend),
    then uses bootc-image-builder to produce a VHDX for Hyper-V import.

.PARAMETER OutputFormat
    Disk image format to produce: vhdx (default), raw, qcow2, wsl2

.PARAMETER Tag
    Local image tag (default: mios:local)

.PARAMETER SkipBib
    Build the container image only; skip bootc-image-builder disk conversion.

.EXAMPLE
    .\Build-MiOS.ps1
    .\Build-MiOS.ps1 -OutputFormat wsl2
    .\Build-MiOS.ps1 -SkipBib
#>
param(
    [ValidateSet('vhdx','raw','qcow2','wsl2')]
    [string]$OutputFormat = 'vhdx',
    [string]$Tag = 'mios:local',
    [switch]$SkipBib
)

Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

# ── Colour helpers ─────────────────────────────────────────────────────────
function Write-Step   { param([string]$Msg) Write-Host "==> $Msg" -ForegroundColor Cyan }
function Write-Ok     { param([string]$Msg) Write-Host " ok $Msg" -ForegroundColor Green }
function Write-Warn   { param([string]$Msg) Write-Host "WARN $Msg" -ForegroundColor Yellow }
function Write-Fail   { param([string]$Msg) Write-Host "FAIL $Msg" -ForegroundColor Red; exit 1 }

# ── Preflight ──────────────────────────────────────────────────────────────
Write-Step "Preflight checks"

if (-not (Get-Command docker -ErrorAction SilentlyContinue)) {
    Write-Fail "docker not found. Install Docker Desktop: https://www.docker.com/products/docker-desktop/"
}
$dockerInfo = docker info 2>&1
if ($LASTEXITCODE -ne 0) {
    Write-Fail "Docker daemon not running. Start Docker Desktop and try again."
}
if ($dockerInfo -notmatch 'WSL') {
    Write-Warn "Docker Desktop does not appear to be using the WSL2 backend. Build may be slower."
}

if (-not (Test-Path 'Containerfile')) {
    Write-Fail "Containerfile not found. Run this script from the 'MiOS' repo root."
}
Write-Ok "Docker Desktop + Containerfile found"

# ── Environment variables ──────────────────────────────────────────────────
Write-Step "Loading build environment"

# Load from the unified ~/.config/mios/mios.toml (or legacy env.toml fallback).
$UnifiedToml = "$HOME\.config\mios\mios.toml"
$LegacyEnv   = "$HOME\.config\mios\env.toml"
$ConfigToml  = if (Test-Path $UnifiedToml) { $UnifiedToml }
               elseif (Test-Path $LegacyEnv) { $LegacyEnv }
               else { $null }
if ($ConfigToml) {
    Write-Ok "Reading $ConfigToml"
    # Flat KEY = "value" lines. Sectioned subkeys (user.name, image.base, ...)
    # not parsed here -- the canonical reader is tools/lib/userenv.sh on the
    # Linux side. This Windows-side loader only needs MIOS_USER_PASSWORD_HASH
    # and MIOS_SSH_PUBKEY which are flat KEY=VALUE in either file.
    Get-Content $ConfigToml | ForEach-Object {
        if ($_ -match '^\s*(MIOS_\w+)\s*=\s*"?([^"#]+)"?') {
            $k = $Matches[1]; $v = $Matches[2].Trim()
            if (-not [System.Environment]::GetEnvironmentVariable($k)) {
                [System.Environment]::SetEnvironmentVariable($k, $v)
                Write-Host "  $k = $v"
            }
        }
    }
}

# Mandatory secrets -- prompt if not set
if (-not $env:MIOS_USER_PASSWORD_HASH) {
    $pw = Read-Host -Prompt "MIOS_USER_PASSWORD_HASH (openssl passwd -6 <password>)"
    $env:MIOS_USER_PASSWORD_HASH = $pw
}
if (-not $env:MIOS_SSH_PUBKEY) {
    $key = Read-Host -Prompt "MIOS_SSH_PUBKEY (your SSH public key, or Enter to skip)"
    if ($key) { $env:MIOS_SSH_PUBKEY = $key }
}

# ── Build OCI image ────────────────────────────────────────────────────────
Write-Step "Building 'MiOS' OCI image ($Tag)"

$BuildArgs = @(
    'build',
    '--tag', $Tag,
    '--file', 'Containerfile',
    '--build-arg', "MIOS_USER_PASSWORD_HASH=$env:MIOS_USER_PASSWORD_HASH"
)
if ($env:MIOS_SSH_PUBKEY) {
    $BuildArgs += '--build-arg', "MIOS_SSH_PUBKEY=$env:MIOS_SSH_PUBKEY"
}
$BuildArgs += '.'

docker @BuildArgs
if ($LASTEXITCODE -ne 0) { Write-Fail "docker build failed (exit $LASTEXITCODE)" }
Write-Ok "OCI image built: $Tag"

if ($SkipBib) {
    Write-Ok "Done (SkipBib set -- skipping disk image conversion)"
    exit 0
}

# ── bootc-image-builder ────────────────────────────────────────────────────
Write-Step "Converting OCI → $OutputFormat via bootc-image-builder"

$OutputDir = Join-Path (Get-Location) 'output'
New-Item -ItemType Directory -Force -Path $OutputDir | Out-Null

# Map format to BIB --type value
$BibType = switch ($OutputFormat) {
    'vhdx'  { 'vhd'   }
    'raw'   { 'raw'   }
    'qcow2' { 'qcow2' }
    'wsl2'  { 'wsl2'  }
}

# BIB config -- substitute env vars
$BibConfig = @"
[[customizations.user]]
name = "mios"
password = "$env:MIOS_USER_PASSWORD_HASH"
$(if ($env:MIOS_SSH_PUBKEY) { 'key = "' + $env:MIOS_SSH_PUBKEY + '"' } else { '' })
groups = ["wheel"]
"@
$BibConfigPath = Join-Path $env:TEMP 'mios-bib.toml'
Set-Content -Path $BibConfigPath -Value $BibConfig -Encoding UTF8

docker run --rm --privileged `
    --security-opt label=type:unconfined_t `
    -v "${OutputDir}:/output" `
    -v "/var/run/docker.sock:/var/run/docker.sock" `
    -v "${BibConfigPath}:/config.toml" `
    "ghcr.io/osbuild/bootc-image-builder:latest" `
    --type $BibType `
    --config /config.toml `
    --local `
    $Tag

if ($LASTEXITCODE -ne 0) { Write-Fail "bootc-image-builder failed (exit $LASTEXITCODE)" }

# Rename vhd → vhdx
if ($OutputFormat -eq 'vhdx') {
    $VhdPath  = Join-Path $OutputDir 'disk.vhd'
    $VhdxPath = Join-Path $OutputDir 'disk.vhdx'
    if (Test-Path $VhdPath) {
        Move-Item -Force $VhdPath $VhdxPath
        Write-Ok "Disk image: $VhdxPath"
    }
} else {
    Write-Ok "Disk image: $(Join-Path $OutputDir "disk.$OutputFormat")"
}

Write-Step "Build complete"
Write-Host ""
Write-Host "  Image tag : $Tag"
Write-Host "  Output    : $OutputDir"
if ($OutputFormat -eq 'vhdx') {
    Write-Host ""
    Write-Host "  Import into Hyper-V:"
    Write-Host "    New-VM -Name 'MiOS' -BootDevice VHD -VHDPath '$OutputDir\disk.vhdx' -Generation 2"
}
